import katex from 'https://cdn.jsdelivr.net/npm/katex@0/+esm';
const style = document.createElement('style'); style.textContent = KATEX_CSS_WITH_DATA_URI_FONTS; document.head.appendChild(style);
const el = document.getElementById('math');
katex.render(data.latex, el, { displayMode: data.displayMode ?? false, throwOnError: data.throwOnError ?? false,
  output: data.output ?? 'htmlAndMathml', trust: data.trust ?? false, macros: data.macros ?? {} });

boot.widget:
// CSS 进 shadow；先把相对字体 URL 改成 pinned 绝对 URL
import katex from 'https://cdn.jsdelivr.net/npm/katex@0/+esm';
const base = 'https://cdn.jsdelivr.net/npm/katex@0.18.1/dist/';
const css = (await fetch(base + 'katex.min.css').then(r => r.text())).replaceAll('url(fonts/', `url(${base}fonts/`);
const style = document.createElement('style'); style.textContent = css; shadowRoot.appendChild(style);
const el = document.createElement('span'); shadowRoot.appendChild(el);
katex.render(data.latex, el, { displayMode: data.displayMode ?? false, throwOnError: data.throwOnError ?? false, output: data.output ?? 'htmlAndMathml', trust: data.trust ?? false, macros: data.macros ?? {} });
